// Server response for a home screen
{
  "screen": {
    "type": "column",
    "padding": 16,
    "children": [
      {
        "type": "text",
        "content": "Welcome back, Ada!",
        "style": "headline"
      },
      { "type": "spacer", "size": 8 },
      {
        "type": "card",
        "backgroundColor": "#f6f8ff",
        "padding": 16,
        "child": {
          "type": "column",
          "children": [
            { "type": "text", "content": "Your points balance" },
            { "type": "text", "content": "1,240", "style": "display" },
            {
              "type": "button",
              "label": "Redeem now",
              "action": { "type": "navigate", "route": "/redeem" }
            }
          ]
        }
      },
      { "type": "list", "itemsFromApi": "/api/products/featured" }
    ]
  }
}

// Client-side renderer — walks the JSON tree, returns Flutter widgets.
Widget renderNode(BuildContext context, Map<String, dynamic> node) {
  return switch (node['type']) {
    'column' => Column(
      children: (node['children'] as List)
          .map<Widget>((c) => renderNode(context, Map<String, dynamic>.from(c)))
          .toList(),
    ),
    'text' => Text(
      node['content'] as String,
      style: _styleFor(node['style']),
    ),
    'spacer' => SizedBox(height: (node['size'] as num).toDouble()),
    'card' => Card(
      color: _colorFromHex(node['backgroundColor']),
      child: Padding(
        padding: EdgeInsets.all((node['padding'] as num).toDouble()),
        child: renderNode(context, Map<String, dynamic>.from(node['child'])),
      ),
    ),
    'button' => FilledButton(
      onPressed: () => _dispatchAction(context, node['action']),
      child: Text(node['label'] as String),
    ),
    'list' => _RemoteList(url: node['itemsFromApi'] as String),
    _ => const SizedBox.shrink(),   // unknown type — gracefully skip
  };
}

void _dispatchAction(BuildContext c, Map<String, dynamic> action) {
  switch (action['type']) {
    case 'navigate':
      c.push(action['route'] as String);
    case 'showSnackbar':
      ScaffoldMessenger.of(c).showSnackBar(SnackBar(content: Text(action['message'])));
    case 'openUrl':
      launchUrl(Uri.parse(action['url'] as String));
    default:
      debugPrint('unknown action: ${action['type']}');
  }
}

// The screen widget just fetches JSON + renders.
class HomeSduiScreen extends StatelessWidget {
  const HomeSduiScreen({super.key});

  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Home')),
    body: FutureBuilder<Map<String, dynamic>>(
      future: dio.get('/api/screens/home').then((r) => r.data),
      builder: (c, snap) {
        if (!snap.hasData) return const CircularProgressIndicator();
        return renderNode(c, snap.data!['screen']);
      },
    ),
  );
}
